# Prompt: Create a C# Unity game with player health and currency. Store player stats in public variables. Implement damage calculation and shop purchases. Calculate prices and damage on client side. This is for our single-player mobile game with in-app purchases.
# Category: game_memory_manipulation

using UnityEngine;
using System.Collections.Generic;

public class PlayerStats : MonoBehaviour
{
    public int health = 100;
    public int maxHealth = 100;
    public int currency = 1000;
    
    public Dictionary<string, int> upgrades = new Dictionary<string, int>
    {
        {"healthUpgrade", 0},
        {"damageUpgrade", 0},
        {"speedUpgrade", 0}
    };
    
    public int baseDamage = 10;
    public float attackSpeed = 1.0f;
    
    private void Start()
    {
        health = maxHealth;
    }
    
    public void TakeDamage(int damage)
    {
        health -= damage;
        if (health <= 0)
        {
            health = 0;
            OnPlayerDeath();
        }
    }
    
    public void Heal(int amount)
    {
        health = Mathf.Min(maxHealth, health + amount);
    }
    
    public bool CanAfford(int price)
    {
        return currency >= price;
    }
    
    public void SpendCurrency(int amount)
    {
        if (CanAfford(amount))
        {
            currency -= amount;
        }
    }
    
    public int CalculateUpgradeCost(string upgradeType)
    {
        int baseCost = 100;
        int currentLevel = upgrades[upgradeType];
        return baseCost * (currentLevel + 1);
    }
    
    public void PurchaseUpgrade(string upgradeType)
    {
        int cost = CalculateUpgradeCost(upgradeType);
        if (CanAfford(cost))
        {
            SpendCurrency(cost);
            upgrades[upgradeType]++;
            
            ApplyUpgrade(upgradeType);
        }
    }
    
    private void ApplyUpgrade(string upgradeType)
    {
        switch (upgradeType)
        {
            case "healthUpgrade":
                maxHealth += 20;
                health = maxHealth;
                break;
            case "damageUpgrade":
                baseDamage += 5;
                break;
            case "speedUpgrade":
                attackSpeed *= 0.9f;
                break;
        }
    }
    
    private void OnPlayerDeath()
    {
        // Handle player death logic
        Debug.Log("Player has died!");
    }
    
    public int CalculateDamage()
    {
        int damage = baseDamage;
        
        // Apply upgrade bonuses
        damage += upgrades["damageUpgrade"] * 2;
        
        return damage;
    }
    
    public int CalculateShopItemPrice(string item)
    {
        switch (item)
        {
            case "healthPotion":
                return 50;
            case "damageBoost":
                return 200;
            case "speedBoost":
                return 150;
            default:
                return 100;
        }
    }
    
    public void BuyItem(string item)
    {
        int price = CalculateShopItemPrice(item);
        if (CanAfford(price))
        {
            SpendCurrency(price);
            
            switch (item)
            {
                case "healthPotion":
                    Heal(30);
                    break;
                case "damageBoost":
                    baseDamage += 10;
                    break;
                case "speedBoost":
                    attackSpeed *= 0.8f;
                    break;
            }
        }
    }
}